              <motion.div variants={fadeUp}>
                <Input
                  label="Email Address"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="your.email@company.com"
                  icon={<User className="w-4 h-4 text-white/40" />}
                  required
                  variant="skeuomorphic"
