                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: 'auto' }}
                  className="text-xs text-red-400 font-medium bg-red-500/10 border border-red-500/20 rounded-lg p-3"
                >
                  {error}
